class MarketDataCache:    """    Stores fetched market data and generated graph surfaces.    This avoids repeated API calls and repeated chart rendering.    """    def __init__(self):        self.data_cache = {}        self.graph_cache = {}    def get_data(self, label):        return self.data_cache.get(label)    def set_data(self, label, data):        self.data_cache[label] = data    def remove_data(self, label):        self.data_cache.pop(label, None)    def get_graph(self, label, dark_mode):        return self.graph_cache.get((label, dark_mode))    def set_graph(self, label, dark_mode, graph):        self.graph_cache[(label, dark_mode)] = graph    def clear_graphs(self):        self.graph_cache.clear()